    {
      "name": "--logLevel",
      "required": false,
      "arguments": [
        {
          "name": "LEVEL",
          "required": true,
          "arity": {
            "minimum": 1,
            "maximum": 1
          },
          "metadata": [
            {
              "name": "ClrType",
              "value": "System.Diagnostics.SourceLevels"
